import React, { useState } from "react";
import { Card, CardBody, Container, Row, Col, Form, FormGroup, Label, Input, Button } from "reactstrap";
import { useNavigate } from "react-router-dom";
import Header from "components/Headers/Header.js";

const AddHealthInsurance = () => {
    const navigate = useNavigate();
    const [healthInsurance, setHealthInsurance] = useState({
        code: "",
        fullName: "",
        placeOfRegistration: "",
        validity: "",
        serialNumber: "",
        issueDate: "",
        placeOfIssue: "",
    });

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setHealthInsurance({ ...healthInsurance, [name]: value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const response = await fetch("http://localhost:5000/api/health-insurance", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(healthInsurance),
            });

            if (response.ok) {
                navigate("/admin/bhyt");
            } else {
                console.error("Lỗi khi thêm BHYT");
            }
        } catch (error) {
            console.error("Lỗi kết nối API:", error);
        }
    };

    return (
        <>
            <Header />
            <Container fluid className="mt-4">
                <Row>
                    <Col>
                        <h3 className="text-dark">Thêm Thẻ BHYT</h3>
                        <p className="text-muted">Quản Lý Thẻ BHYT / Thêm Thẻ BHYT</p>
                    </Col>
                </Row>

                <Card className="mt-4">
                    <CardBody>
                        <Form onSubmit={handleSubmit}>
                            <Row>
                                <Col md="6">
                                    <h4 className="text-dark">Thông tin cơ bản</h4>
                                    {Object.keys(healthInsurance).map((key) => (
                                        <FormGroup key={key}>
                                            <Label for={key}>{key}</Label>
                                            <Input
                                                type={key.includes("Date") ? "date" : "text"}
                                                id={key}
                                                name={key}
                                                placeholder={`Nhập ${key}`}
                                                value={healthInsurance[key]}
                                                onChange={handleInputChange}
                                                required
                                            />
                                        </FormGroup>
                                    ))}
                                    <Button color="success" type="submit" className="mr-2">Lưu Lại</Button>
                                    <Button color="danger" onClick={() => navigate("/admin/bhyt")}>Quay lại</Button>
                                </Col>
                            </Row>
                        </Form>
                    </CardBody>
                </Card>
            </Container>
        </>
    );
};

export default AddHealthInsurance;
